<script lang="ts">
  const injFade = Symbol();
</script>

<script setup lang="ts">
  import { Transition, TransitionGroup } from 'vue';

  const { group, tag = 'div' } = defineProps<{
    group?: boolean;
    tag?: string;
  }>();

  const isRunning = ref(false);

  const parentFade = inject(injFade, { isRunning: ref(false) });
  provide(injFade, { isRunning });

  const component = $computed(() =>
    parentFade.isRunning.value ? tag : group ? TransitionGroup : Transition,
  );
</script>

<template>
  <Component
    :is="component"
    :tag="tag"
    name="fade"
    @before-leave="(el:HTMLElement) => {
      isRunning = true;
      beforeLeaveKeepTransform(el)
    }"
    @after-enter="isRunning = false"
    @before-enter="isRunning = true"
    @after-leave="isRunning = false"
  >
    <slot></slot>
  </Component>
</template>

<style lang="scss" scoped>
  :deep(> *) {
    @apply transition-all duration-300 ease-in-out;

    &.fade-enter-from,
    &.fade-leave-to {
      @apply opacity-0;
    }

    &.fade-leave-from,
    &.fade-enter-to {
      @apply opacity-100;
    }

    &.fade-leave-active {
      @apply absolute;
    }
  }
</style>
